\begin{parts}
\item
\begin{subparts}
\item Show that the equation $y = (x - 4)(x + 1)(x - 2)$ can be written as $y = x^3 - 5x^2 + 2x + 8$.
\Answerspace[3cm]
\Marks{2}

\item On the diagram, sketch the graph of $y = x^3 - 5x^2 + 2x + 8$, indicating the values where the graph crosses the axes.

\begin{InsertScreenShot}
    \relincludegraphics{Figures/Q08-Grid.png}
\end{InsertScreenShot}
\Marks{4}
\end{subparts}

\item The graph of $y = x^3 - 5x^2 + 2x + 8$ has two tangents with a gradient of 10.

Find the equations of these two tangents.
You must show all your working and give your answers in the form $y = mx + c$.

\AnswerLine[$y=$][]
\AnswerLine[$y=$][]
\Marks{7}
\end{parts}

\begin{parts}
\item Simplify.
\begin{subparts}
\item $(3x^2 y^4)^3$
\AnswerLine[][]
\Marks{2}

\item $\left( \dfrac{16}{x^{16} y^8} \right)^{-\frac{3}{2}}$
\AnswerLine[][]
\Marks{3}
\end{subparts}

\item
\begin{subparts}
\item Factorise.
\[ x^2 - 9 \]
\AnswerLine[][]
\Marks{1}

\item Simplify.
\[ \dfrac{x^2 - 9}{2xy - 6y + 5x - 15} \]
\AnswerLine[][]
\Marks{3}
\end{subparts}

\item Solve the simultaneous equations.
You must show all your working and give your answers correct to 2 decimal places.
\begin{align*}
2x + y &= 7 \\
y &= 5x^2 + 2x - 13
\end{align*}

\AnswerLine[$x=$][, $y=$]
\AnswerLine[$x=$][, $y=$]
\Marks{6}
\end{parts}

